def kruskal_mst(n, edges):
    parent = list(range(n))
    rank = [0] * n
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    def union(a, b):
        ra, rb = find(a), find(b)
        if ra == rb:
            return False
        if rank[ra] < rank[rb]:
            parent[ra] = rb
        elif rank[ra] > rank[rb]:
            parent[rb] = ra
        else:
            parent[rb] = ra
            rank[ra] += 1
        return True
    total = 0
    picked = 0
    for u, v, w in sorted(edges, key=lambda x: x[2]):
        if union(u, v):
            total += w
            picked += 1
            if picked == n - 1:
                break
    return total if picked == n - 1 else None

